{
  "executive_summary": "This system exhibits five distinct architectural anti-patterns that have compounded over 3 years of organic growth. The most critical issues are the shared database between Order and Courier services (destroying service autonomy), and the Reporting Service's direct database reads (creating invisible coupling). The synchronous Notification fan-in, the god endpoint on Customer Service, and HTTP-based background jobs each add operational risk and brittleness. Remediation should be sequenced to address data coupling first (highest blast radius), then communication patterns, then API design.",

  "architecture": {
    "components": [
      { "name": "Order Service", "responsibility": "Order lifecycle management", "boundaries": "VIOLATED — shares database with Courier, tables read directly by Reporting" },
      { "name": "Courier Service", "responsibility": "Delivery assignment and tracking", "boundaries": "VIOLATED — shares database with Order Service" },
      { "name": "Notification Service", "responsibility": "Fan-out notifications (email, push, SMS)", "boundaries": "Structurally correct but operationally fragile — synchronous coupling to 5 callers" },
      { "name": "Payment Service", "responsibility": "Payment processing and refunds", "boundaries": "Reasonable, but refund processing exposed as REST job endpoint" },
      { "name": "Customer Service", "responsibility": "Customer identity, preferences, addresses, payment methods, order history", "boundaries": "VIOLATED — god endpoint conflates multiple bounded contexts into one response" },
      { "name": "Reporting Service", "responsibility": "Analytics and business reporting", "boundaries": "VIOLATED — bypasses Order Service API and reads tables directly" }
    ],
    "interfaces": [
      { "from": "Order Service", "to": "Notification Service", "contract": "Synchronous REST call", "coupling_type": "temporal + behavioral" },
      { "from": "Courier Service", "to": "Notification Service", "contract": "Synchronous REST call", "coupling_type": "temporal + behavioral" },
      { "from": "Payment Service", "to": "Notification Service", "contract": "Synchronous REST call", "coupling_type": "temporal + behavioral" },
      { "from": "Customer Service", "to": "Notification Service", "contract": "Synchronous REST call", "coupling_type": "temporal + behavioral" },
      { "from": "Reporting Service", "to": "Notification Service", "contract": "Synchronous REST call", "coupling_type": "temporal + behavioral" },
      { "from": "Order Service", "to": "Shared PostgreSQL", "contract": "Direct table read/write (order_ prefix)", "coupling_type": "database-level (strongest possible)" },
      { "from": "Courier Service", "to": "Shared PostgreSQL", "contract": "Direct table read/write (courier_ prefix)", "coupling_type": "database-level (strongest possible)" },
      { "from": "Reporting Service", "to": "Order Service DB tables", "contract": "Direct SQL reads against order tables", "coupling_type": "database-level (invisible dependency)" },
      { "from": "Cron scheduler", "to": "Payment Service /api/v1/jobs/process-refunds", "contract": "HTTP GET/POST to trigger background work", "coupling_type": "temporal + transport misuse" },
      { "from": "Any consumer", "to": "Customer Service /api/v1/everything", "contract": "Returns full customer aggregate", "coupling_type": "semantic (over-fetching, god endpoint)" }
    ],
    "data_flow": "Order and Courier services share a single PostgreSQL instance with schema prefixes as the only isolation boundary. Reporting reads Order tables directly via SQL, bypassing the Order API entirely. Five services make synchronous HTTP calls to Notification for every event. Background refund processing is triggered by an external cron hitting a REST endpoint. Customer data is served as a monolithic blob through a single endpoint.",
    "patterns_used": [
      { "pattern": "Shared Database (anti-pattern)", "rationale": "Likely started as a monolith and was split into services without splitting the database" },
      { "pattern": "Synchronous Fan-In (anti-pattern)", "rationale": "Notification was easy to call directly; no messaging infrastructure existed early on" },
      { "pattern": "God Endpoint (anti-pattern)", "rationale": "Evolved from convenience — one call gets everything — rather than intentional API design" },
      { "pattern": "HTTP-triggered Jobs (anti-pattern)", "rationale": "Team reused existing REST framework rather than adopting a job queue" },
      { "pattern": "Direct Database Consumer (anti-pattern)", "rationale": "Reporting needed data fast and the API didn't expose the right queries" }
    ]
  },

  "domain_model": {
    "bounded_contexts": [
      { "name": "Order Management", "classification": "core", "aggregates": ["Order", "OrderLine", "OrderStatus"] },
      { "name": "Courier & Delivery", "classification": "core", "aggregates": ["Delivery", "CourierAssignment", "Route"] },
      { "name": "Customer Identity", "classification": "supporting", "aggregates": ["Customer", "Address", "Preference"] },
      { "name": "Payment", "classification": "core", "aggregates": ["Payment", "Refund", "PaymentMethod"] },
      { "name": "Notification", "classification": "generic", "aggregates": ["NotificationRequest", "NotificationTemplate", "DeliveryChannel"] },
      { "name": "Reporting & Analytics", "classification": "supporting", "aggregates": ["Report", "ReportDefinition"] }
    ],
    "context_map": [
      { "upstream": "Order Management", "downstream": "Courier & Delivery", "relationship": "SHOULD BE Customer-Supplier via events; CURRENTLY Shared Kernel (shared DB)" },
      { "upstream": "Order Management", "downstream": "Reporting & Analytics", "relationship": "SHOULD BE Open Host Service or event stream; CURRENTLY direct DB access (no boundary)" },
      { "upstream": "All Services", "downstream": "Notification", "relationship": "SHOULD BE Published Language via async events; CURRENTLY synchronous Conformist" },
      { "upstream": "Customer Identity", "downstream": "All consumers", "relationship": "SHOULD BE Open Host Service with focused query endpoints; CURRENTLY god endpoint" }
    ]
  },

  "trade_offs": [
    {
      "decision": "Split shared Order/Courier database into separate databases",
      "gains": "Independent deployability, schema evolution autonomy, failure isolation, enables independent scaling",
      "sacrifices": "Cross-service queries become harder, need to implement event-based sync, temporary data duplication, migration effort is significant",
      "alternatives_considered": ["Schema-level isolation with stricter access controls (half-measure — delays the real fix)", "Database views as a read-only contract (better than raw tables but still coupled at deploy time)"]
    },
    {
      "decision": "Replace synchronous Notification calls with async message queue",
      "gains": "Callers are decoupled from Notification availability, Notification can scale independently, retry/DLQ for free, no cascading failures",
      "sacrifices": "Notifications become eventually consistent (slight delay), need to operate message broker, debugging is harder (distributed tracing needed)",
      "alternatives_considered": ["Async HTTP with webhooks (simpler but still point-to-point)", "Keep sync but add circuit breakers (band-aid — doesn't fix the fundamental coupling)"]
    },
    {
      "decision": "Replace /api/v1/everything with focused endpoints",
      "gains": "Clients fetch only what they need, each endpoint can be optimized/cached independently, clearer API contract, enables BFF pattern later",
      "sacrifices": "Clients making one call today will need multiple calls or a composite endpoint, migration requires client coordination",
      "alternatives_considered": ["GraphQL on Customer Service (powerful but adds complexity for what should be a simple CRUD service)", "Keep god endpoint but add sparse fieldsets via query params (half-measure that doesn't fix the domain boundary issue)"]
    },
    {
      "decision": "Move background jobs to a proper job queue (e.g., Sidekiq, BullMQ, or Celery)",
      "gains": "Retry logic, backpressure, visibility into job state, no HTTP timeout risk, concurrent execution control",
      "sacrifices": "New infrastructure dependency (Redis/RabbitMQ), team needs to learn job queue patterns",
      "alternatives_considered": ["Keep HTTP but add internal-only auth and timeout guards (still misuses HTTP semantics)", "Database-backed job table with polling (works but reinvents existing solutions)"]
    },
    {
      "decision": "Replace Reporting's direct DB reads with a dedicated read model or event-sourced projection",
      "gains": "Order Service can evolve schema freely, Reporting gets an optimized read model, clear ownership boundary",
      "sacrifices": "Reporting data becomes eventually consistent, need to build and maintain projection pipeline",
      "alternatives_considered": ["CDC (Change Data Capture) via Debezium into a reporting database (excellent option, may be preferred if team has Kafka)", "Read-only database replica with published view contract (simpler but still couples schema)"]
    }
  ],

  "flexibility_points": [
    { "area": "Notification delivery mechanism", "evolution_path": "Once async, can swap email providers, add channels (Slack, in-app), implement batching/digests without touching any caller" },
    { "area": "Customer Service API surface", "evolution_path": "Focused endpoints enable per-endpoint caching, rate limiting, versioning, and eventual extraction of Payment Methods into Payment context" },
    { "area": "Reporting data pipeline", "evolution_path": "Event-based projection allows adding new report types, new data sources, and switching analytics backends without touching source services" },
    { "area": "Job processing infrastructure", "evolution_path": "Proper job queue enables priority queues, scheduled jobs, rate limiting, and horizontal scaling of workers independently" }
  ],

  "rigidity_points": [
    { "area": "Order-Courier shared database", "reason": "Any schema migration on shared tables requires coordinated deployment of both services. This is the single biggest constraint on team velocity." },
    { "area": "Notification Service availability", "reason": "5 synchronous callers means Notification downtime cascades to all core flows. A 30-second Notification outage effectively means a 30-second platform outage." },
    { "area": "Customer /everything endpoint", "reason": "Cannot deprecate any field without auditing all consumers. Cannot optimize for specific use cases. The endpoint is effectively frozen." },
    { "area": "Reporting-to-Order table coupling", "reason": "Order Service cannot rename columns, change types, or restructure tables without breaking Reporting. Order team has lost control of their own schema." }
  ],

  "risks": [
    {
      "risk": "Shared database enables cross-service data corruption — Courier could write to Order tables (schema prefix is convention, not enforcement)",
      "severity": "critical",
      "mitigation": "Immediate: add database-level role permissions so each service's credentials can only access its own prefix. Medium-term: split into separate databases."
    },
    {
      "risk": "Notification Service failure causes cascading failures across all 5 calling services, potentially taking down the entire platform",
      "severity": "critical",
      "mitigation": "Immediate: add circuit breakers (Hystrix/Resilience4j) on all Notification callers with fallback to async retry. Medium-term: move to message queue."
    },
    {
      "risk": "HTTP-triggered refund job has no timeout protection — long-running refund batch could exceed HTTP timeout, be retried by cron, and process refunds twice",
      "severity": "critical",
      "mitigation": "Immediate: add idempotency keys to refund processing and mutual exclusion lock. Medium-term: move to proper job queue with at-most-once delivery guarantees."
    },
    {
      "risk": "Reporting's direct DB reads create invisible coupling — Order schema changes break Reporting with no compile-time or contract-time signal",
      "severity": "high",
      "mitigation": "Immediate: create database views as a published contract that Order team owns. Medium-term: move to CDC or event-projected read model."
    },
    {
      "risk": "/api/v1/everything endpoint returns payment methods — any consumer of customer data gets PCI-scoped data whether they need it or not",
      "severity": "high",
      "mitigation": "Immediate: audit all callers and confirm PCI compliance posture. Split payment methods into a separate, access-controlled endpoint."
    },
    {
      "risk": "No service can be independently deployed or scaled due to shared database and synchronous dependencies",
      "severity": "high",
      "mitigation": "Address via the phased remediation plan below — this is the aggregate effect of all anti-patterns."
    }
  ],

  "implementation_guidance": {
    "recommended_approach": "Phase the remediation over 4 quarters. Do NOT attempt a big-bang rewrite. Each phase delivers independent value and reduces risk.\n\n**Phase 1 (Weeks 1-4): Stop the bleeding**\n- Add DB role permissions to enforce schema prefix isolation (Order can't write Courier tables and vice versa)\n- Add circuit breakers on all 5 Notification callers with async fallback\n- Add idempotency keys to refund job processing\n- Audit /everything endpoint consumers for PCI scope exposure\n\n**Phase 2 (Weeks 5-12): Decouple Notification**\n- Introduce a message broker (RabbitMQ or SQS — pick based on existing infra)\n- Define a NotificationRequested event schema (Published Language)\n- Migrate callers one-by-one to publish events instead of synchronous calls\n- Notification Service subscribes to the queue\n- Keep synchronous endpoint alive during migration with feature flags\n\n**Phase 3 (Weeks 13-20): Split the shared database**\n- Create a separate PostgreSQL instance for Courier Service\n- Implement Change Data Capture or domain events for data that Courier needs from Orders\n- Define explicit API contracts for any cross-service queries\n- Migrate Courier writes first, then reads, with a dual-write transition period\n- Simultaneously: create published database views for Reporting, then migrate to CDC/event projection\n\n**Phase 4 (Weeks 21-28): API and Jobs cleanup**\n- Split /api/v1/everything into: /customers/{id}/profile, /customers/{id}/addresses, /customers/{id}/preferences, /customers/{id}/order-history (redirect to Order Service)\n- Extract payment methods to Payment Service's domain\n- Replace HTTP job endpoints with proper job queue (Sidekiq/BullMQ/Celery)\n- Implement job dashboard for visibility",
    "files_to_create_or_modify": [
      "infrastructure/database/role-permissions.sql — Enforce schema-prefix access per service",
      "libs/notification-client/circuit-breaker-config.{ts,py,java} — Shared circuit breaker wrapper for Notification calls",
      "services/payment/jobs/process-refunds-worker.{ts,py,java} — New job queue worker replacing HTTP endpoint",
      "services/notification/consumers/notification-event-consumer.{ts,py,java} — Queue subscriber",
      "schemas/events/notification-requested.avsc (or .json) — Published event schema",
      "services/customer/routes/profile.{ts,py,java} — Focused profile endpoint",
      "services/customer/routes/addresses.{ts,py,java} — Focused addresses endpoint",
      "services/customer/routes/preferences.{ts,py,java} — Focused preferences endpoint",
      "infrastructure/database/reporting-views.sql — Published view contract for Reporting",
      "infrastructure/cdc/order-events-connector.json — Debezium/CDC config for Order table changes",
      "docs/adr/001-split-shared-database.md",
      "docs/adr/002-async-notifications.md",
      "docs/adr/003-customer-api-decomposition.md",
      "docs/adr/004-job-queue-migration.md"
    ],
    "patterns_to_follow": "Strangler Fig for all migrations — new pattern runs alongside old, traffic shifts gradually, old path removed only after validation. Published Language for event schemas. Anti-Corruption Layer between Courier and Order during database split transition. Circuit Breaker on all synchronous cross-service calls that remain.",
    "pitfalls_to_avoid": [
      "Do NOT split the database before establishing event contracts — you'll create a different coupling problem",
      "Do NOT introduce a message broker without dead-letter queues and monitoring from day one",
      "Do NOT deprecate /api/v1/everything before all consumers have migrated — use analytics/logging to verify zero traffic first",
      "Do NOT assume schema prefixes provide isolation — they are naming conventions, not security boundaries",
      "Do NOT dual-write to two databases without idempotency — you will get inconsistencies",
      "Do NOT skip the circuit breaker phase — async migration takes time and Notification will fail during that window"
    ]
  },

  "escalations": [],

